import * as React from "react"
import { cn } from "@/lib/utils"

export interface Property {
  key: string
  label: string
  type: "text" | "number" | "color" | "select" | "slider"
  value: any
  options?: { label: string; value: any }[]
  min?: number
  max?: number
  step?: number
  unit?: string
  onChange?: (value: any) => void
}

export interface PropertyPanelProps {
  title?: string
  properties: Property[]
  onChange?: (key: string, value: any) => void
  className?: string
}

const PropertyItem: React.FC<{
  property: Property
  onChange?: (key: string, value: any) => void
}> = ({ property, onChange }) => {
  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onChange?.(property.key, property.type === 'number' ? parseFloat(e.target.value) : e.target.value)
  }

  const handleSelectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    onChange?.(property.key, e.target.value)
  }

  const handleSliderChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onChange?.(property.key, parseFloat(e.target.value))
  }

  switch (property.type) {
    case "text":
      return (
        <div className="property-item">
          <label className="property-label">{property.label}</label>
          <input
            type="text"
            value={property.value || ""}
            onChange={handleInputChange}
            className="property-input"
          />
        </div>
      )

    case "number":
      return (
        <div className="property-item">
          <label className="property-label">{property.label}</label>
          <input
            type="number"
            value={property.value ?? 0}
            onChange={handleInputChange}
            className="property-input"
          />
        </div>
      )

    case "color":
      return (
        <div className="property-item">
          <label className="property-label">{property.label}</label>
          <div className="flex items-center gap-2">
            <input
              type="color"
              value={property.value || "#000000"}
              onChange={handleInputChange}
              className="w-10 h-10 rounded cursor-pointer"
            />
            <input
              type="text"
              value={property.value || ""}
              onChange={handleInputChange}
              className="property-input flex-1"
            />
          </div>
        </div>
      )

    case "select":
      return (
        <div className="property-item">
          <label className="property-label">{property.label}</label>
          <select
            value={property.value ?? ""}
            onChange={handleSelectChange}
            className="property-select"
          >
            {property.options?.map((option) => (
              <option key={option.value} value={option.value}>
                {option.label}
              </option>
            ))}
          </select>
        </div>
      )

    case "slider":
      return (
        <div className="property-item">
          <label className="property-label">{property.label}</label>
          <div className="flex items-center gap-2 flex-1">
            <input
              type="range"
              value={property.value ?? 0}
              onChange={handleSliderChange}
              min={property.min}
              max={property.max}
              step={property.step}
              className="flex-1"
              style={{ flex: 1 }}
            />
            <input
              type="number"
              value={property.value ?? 0}
              onChange={handleInputChange}
              min={property.min}
              max={property.max}
              step={property.step}
              className="property-input"
              style={{ minWidth: "60px", width: "60px" }}
            />
            {property.unit && <span className="text-xs text-slate-500">{property.unit}</span>}
          </div>
        </div>
      )

    default:
      return null
  }
}

export const PropertyPanel = React.forwardRef<HTMLDivElement, PropertyPanelProps>(
  (
    {
      title = "属性",
      properties = [],
      onChange,
      className,
    },
    ref
  ) => {
    // 添加调试日志
    React.useEffect(() => {
      console.log('[PropertyPanel] properties 更新:', properties.length, '个属性')
      console.log('[PropertyPanel] properties 详情:', properties.map(p => ({ key: p.key, label: p.label, value: p.value })))
    }, [properties])

    const handlePropertyChange = (key: string, value: any) => {
      console.log('[PropertyPanel] 属性变化:', key, '=', value)
      onChange?.(key, value)
    }

    // 分组属性
    const groupedProperties = React.useMemo(() => {
      const groups: Record<string, Property[]> = {}

      properties.forEach((prop) => {
        const group = prop.key.split(".")[0]
        if (!groups[group]) {
          groups[group] = []
        }
        groups[group].push(prop)
      })

      console.log('[PropertyPanel] 分组后的属性:', Object.keys(groups), '->', Object.values(groups).map(g => g.length))

      return groups
    }, [properties])

    return (
      <div ref={ref} className={cn("property-panel", className)}>
        <div className="property-panel-header">
          <h3 className="text-sm font-semibold">{title}</h3>
        </div>

        <div className="property-panel-content">
          {Object.entries(groupedProperties).map(([groupName, groupProps]) => (
            <div key={groupName} className="property-group">
              <h4 className="property-group-title">{groupName}</h4>
              {groupProps.map((prop) => (
                <PropertyItem
                  key={prop.key}
                  property={prop}
                  onChange={handlePropertyChange}
                />
              ))}
            </div>
          ))}

